<div class="page-head"><h1>Tiện ích</h1><a class="btn" href="/amenities/create">Thêm tiện ích</a></div>
<table><tr><th>Tên</th><th>Mô tả</th><th></th></tr><?php foreach ($amenities as $amenity): ?><tr><td><?= e($amenity['name']) ?></td><td><?= e($amenity['description']) ?></td><td class="actions"><a class="btn secondary" href="/amenities/<?= e($amenity['amenity_id']) ?>/edit">Sửa</a><form class="inline" method="post" action="/amenities/<?= e($amenity['amenity_id']) ?>"><?= csrf_field() ?><?= method_field('DELETE') ?><button class="danger" data-confirm="Xóa tiện ích?">Xóa</button></form></td></tr><?php endforeach; ?></table>
